import java.util.HashMap;
import java.util.Map;

public class OrderProcessor {
    private Map<String, Integer> priceList = new HashMap<>();

    // Method to add products and their prices to the price list
    public void addProduct(String productName, int price) {
        priceList.put(productName, price);
    }

    // Method to query the price of a product
    public int queryPrice(String productName) {
        return priceList.getOrDefault(productName, 0); // Return 0 if the product is not found
    }

    public static void main(String[] args) {
        OrderProcessor processor = new OrderProcessor();

        // Add products and their prices to the price list
        processor.addProduct("Apple", 1.5);
        processor.addProduct("Banana", 0.8);
        processor.addProduct("Cherry", 2.0);

        String orderString = "Apple–1–2";
        String[] orderData = orderString.split("\\s+");
        String[] productDetails = orderData[0].split("–");
        int productPrice = processor.queryPrice(productDetails[1]);
        int orderPrice = Integer.parseInt(orderData[1]) * productPrice;

        System.out.println("Order Price: " + orderPrice);
    }
}
```

